# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request
from flask_login import login_required, current_user

app = Flask(__name__)

class User:
    def __init__(self, email, username, role, account_status, subscription_tier):
        self.email = email
        self.username = username
        self.role = role
        self.account_status = account_status
        self.subscription_tier = subscription_tier

users = {}  # dictionary to store user data

@app.route('/api/users/<user_id>', methods=['PUT'])
@login_required
def update_user(user_id):
    if current_user.role != 'admin':
        return {"error": "Only admins can update user data."}, 403

    if user_id not in users:
        return {"error": "User not found."}, 404

    user_data = request.json
    user = users[user_id]

    if 'email' in user_data:
        user.email = user_data['email']
    if 'username' in user_data:
        user.username = user_data['username']
    if 'role' in user_data:
        user.role = user_data['role']
    if 'account_status' in user_data:
        user.account_status = user_data['account_status']
    if 'subscription_tier' in user_data:
        user.subscription_tier = user_data['subscription_tier']

    return {"message": "User updated successfully."}, 200